// ============================================================
// STEP 1 — EXTRACT JOB DETAILS + CLIENT NAME
// ============================================================
const body = $input.first().json.body;

// ── Job info (from top-level payload fields — v2-hybrid) ────
const jobTitle       = body.jobTitle ?? 'N/A';
const jobDescription = body.description ?? '';
const jobType        = body.jobType ?? 'N/A';
const jobCiphertext  = body.jobCiphertext ?? '';
const jobUrl         = jobCiphertext ? `https://www.upwork.com/jobs/${jobCiphertext}` : 'N/A';
const jobStatus      = body.jobStatus ?? 'N/A';
const jobCategory    = body.jobCategory ?? 'N/A';
const postedOn       = body.postedOn ?? 'N/A';
const skills         = (body.skills ?? []).join(', ');

// Budget
const hourlyMin      = body.hourlyBudget?.hourlyBudgetMin ?? null;
const hourlyMax      = body.hourlyBudget?.hourlyBudgetMax ?? null;
const budget         = body.budget?.amount ?? null;
const budgetCurrency = body.budget?.currencyCode ?? 'USD';

// ── Client stats (from top-level payload) ───────────────────
const clientCountry       = body.clientCountry ?? 'N/A';
const clientCity          = body.clientCity ?? 'N/A';
const clientScore         = body.clientScore ?? 0;
const totalJobsPosted     = body.totalJobsPosted ?? 0;
const totalHired          = body.totalHired ?? 0;
const totalSpent          = body.totalSpent ?? 0;
const totalHoursWorked    = body.totalHoursWorked ?? 0;
const feedbackCount       = body.feedbackCount ?? 0;
const activeContracts     = body.activeContracts ?? 0;
const paymentVerified     = body.paymentVerified ?? false;
const enterprise          = body.enterprise ?? false;
const totalApplicants     = body.totalApplicants ?? 0;
const totalInvitedToInterview = body.totalInvitedToInterview ?? 0;
const numberOfPositions   = body.numberOfPositions ?? 1;
const lastBuyerActivity   = body.lastBuyerActivity ?? 'N/A';
const companyContractDate = body.companyContractDate ?? null;
const companyId           = body.companyId ?? null;

// ── Company name from clientCompanyMetadata (_raw) ──────────
const metaName = body._raw?.clientCompanyMetadata?.data?.clientCompanyMetadata?.name ?? null;
// Also check top-level companyName sent by extension
const topLevelName = body.companyName ?? null;
// Use metaName first (most reliable), then top-level
const rawClientName = metaName ?? topLevelName ?? null;

// ── Work history for AI context ─────────────────────────────
const workHistory = body._raw?.jobAuthDetails?.data?.jobAuthDetails?.buyer?.workHistory ?? [];
const workHistoryTitles = workHistory
  .map(w => w.jobInfo?.title)
  .filter(Boolean)
  .slice(0, 15)
  .join(' | ');
const workHistoryContractors = workHistory
  .map(w => w.contractorInfo?.contractorName)
  .filter(Boolean)
  .slice(0, 10)
  .join(', ');
const feedbackComments = workHistory
  .flatMap(w => [w.feedback?.comment, w.feedbackToClient?.comment])
  .filter(Boolean)
  .join(' ');

// ── Agency staffs ────────────────────────────────────────────
const staffs = (body._raw?.agencyStaffs?.data?.agencyStaffsAuth?.staffs ?? []).map(s => ({
  name: s.personalData?.name ?? 'Unknown',
  ciphertext: s.personalData?.ciphertext ?? '',
  profileUrl: s.personalData?.ciphertext
    ? `https://www.upwork.com/freelancers/${s.personalData.ciphertext}`
    : '',
  topRated: s.personalData?.topRatedStatus,
  memberType: s.memberType
}));

// ── clientDetails (freelancer profiles enrichment) ──────────
const clientDetails = body.clientDetails ?? [];
const clientsWithAgencies = clientDetails
  .filter(c => c.agencies && c.agencies.length > 0)
  .flatMap(c => c.agencies.map(a => ({
    clientName: c.name,
    agencyName: a.name ?? null
  })));
const agencyCompanyName = clientsWithAgencies[0]?.agencyName ?? null;

// ── Open jobs ────────────────────────────────────────────────
const openJobsList = (body._raw?.jobAuthDetails?.data?.jobAuthDetails?.buyer?.info?.jobs?.openJobs ?? [])
  .map(j => j.title).filter(Boolean);

return [{
  json: {
    // Job
    jobTitle,
    jobDescription,
    jobUrl,
    jobType,
    jobStatus,
    jobCategory,
    postedOn,
    skills,
    hourlyMin,
    hourlyMax,
    budget,
    budgetCurrency,
    // Client
    clientCountry,
    clientCity,
    clientScore,
    totalJobsPosted,
    totalHired,
    totalSpent,
    totalHoursWorked,
    feedbackCount,
    activeContracts,
    paymentVerified,
    enterprise,
    totalApplicants,
    totalInvitedToInterview,
    numberOfPositions,
    lastBuyerActivity,
    companyContractDate,
    companyId,
    // Name to classify
    rawClientName,
    agencyCompanyName,
    // Context for AI company reveal
    workHistoryTitles,
    workHistoryContractors,
    feedbackComments: feedbackComments.slice(0, 500),
    openJobsList: openJobsList.join(' | '),
    // Staff
    staffs: JSON.stringify(staffs),
    clientsWithAgencies: JSON.stringify(clientsWithAgencies)
  }
}];

// Company path — AI agent only carries 'output'; get original fields from Extract node
const aiOut = $input.first().json;
const orig  = $('Extract Job + Name').first().json;
const classifiedName = aiOut.output?.name ?? orig.rawClientName ?? orig.agencyCompanyName ?? 'Unknown';
return [{
  json: {
    ...orig,
    companyName: classifiedName,
    companySource: 'metadata',
    nameType: 'company'
  }
}];

parameters.text:
=Try to identify the real company name behind this Upwork client.

The client's Upwork display name is: {{ $json.rawClientName }}
This appears to be a PERSON name, not a company name.

JOB TITLE: {{ $json.jobTitle }}

JOB DESCRIPTION (first 800 chars):
{{ $json.jobDescription.slice(0, 800) }}

JOB CATEGORY: {{ $json.jobCategory }}

PAST JOB TITLES HIRED FOR:
{{ $json.workHistoryTitles }}

PAST CONTRACTOR NAMES:
{{ $json.workHistoryContractors }}

FEEDBACK COMMENTS:
{{ $json.feedbackComments }}

OPEN JOBS:
{{ $json.openJobsList }}

LOCATION: {{ $json.clientCity }}, {{ $json.clientCountry }}

Based on all this information, what is the most likely company name this person works for or owns?
If you cannot determine a company name with reasonable confidence, return the person's name as-is.

Respond ONLY with valid JSON, no markdown:
{"companyName": "Acme Corp", "confidence": "high", "reasoning": "brief reason"}

parameters.jsCode:
// Person path — AI agent only carries 'output'; get original fields from Extract node
const aiOut = $input.first().json;
const orig  = $('Extract Job + Name').first().json;
const revealedName = aiOut.output?.companyName ?? orig.rawClientName ?? 'Unknown';
const confidence   = aiOut.output?.confidence ?? 'low';
const reasoning    = aiOut.output?.reasoning ?? '';
return [{
  json: {
    ...orig,
    companyName: revealedName,
    companySource: 'ai-revealed',
    aiRevealConfidence: confidence,
    aiRevealReasoning: reasoning,
    nameType: 'person',
    personName: orig.rawClientName
  }
}];

// ============================================================
// STEP 2 — FORMAT LEAD + TELEGRAM MESSAGE
// ============================================================
const d = $input.first().json;

// Parse staffs
let staffs = [];
try { staffs = JSON.parse(d.staffs || '[]'); } catch(e) {}

// ── Lead scoring ─────────────────────────────────────────────
let score = 0;
const reasons = [];

if (d.paymentVerified)          { score += 30; reasons.push('✅ Payment verified'); }
if (d.totalSpent > 10000)        { score += 20; reasons.push(`💰 $${(d.totalSpent/1000).toFixed(1)}K spent`); }
else if (d.totalSpent > 1000)    { score += 10; reasons.push(`💰 $${Math.round(d.totalSpent)} spent`); }
if (d.clientScore >= 4.5)        { score += 15; reasons.push(`⭐ ${d.clientScore} rating`); }
if (d.totalHired > 5)            { score += 10; reasons.push(`🤝 ${d.totalHired} hires`); }
if (d.totalApplicants < 30)      { score += 10; reasons.push(`🎯 Only ${d.totalApplicants} applicants`); }
if (d.budget > 500 || d.hourlyMax > 50) { score += 15; reasons.push('💵 Good budget'); }

const grade = score >= 70 ? '🔥 HOT' : score >= 45 ? '🟡 WARM' : '🔵 COLD';

// ── Budget string ────────────────────────────────────────────
let budgetStr = 'N/A';
if (d.hourlyMin && d.hourlyMax)  budgetStr = `$${d.hourlyMin}–$${d.hourlyMax}/hr`;
else if (d.budget)               budgetStr = `$${d.budget} ${d.jobType === 'FIXED' ? 'fixed' : ''}`;

// ── Spent string ─────────────────────────────────────────────
const spentStr = (d.totalSpent ?? 0) >= 1000
  ? `$${((d.totalSpent ?? 0)/1000).toFixed(1)}K`
  : `$${(d.totalSpent ?? 0)}`;

// ── Staff lines ───────────────────────────────────────────────
const staffLines = staffs
  .map(s => {
    const badge = s.topRated === 'top_rated' ? ' ⭐' : '';
    return s.profileUrl
      ? `  👤 <a href="${s.profileUrl}">${s.name}</a>${badge}`
      : `  👤 ${s.name}${badge}`;
  }).join('\n') || '  No profiles found';

// ── Company name + source badge ───────────────────────────────
const nameSourceBadge = d.companySource === 'ai-revealed'
  ? ` <i>(AI revealed, ${d.aiRevealConfidence ?? 'low'} confidence)</i>`
  : ` <i>(${d.companySource ?? 'api'})</i>`;

const personLine = d.nameType === 'person'
  ? `\n• <b>Contact:</b> ${d.personName}`
  : '';

// ── Description truncated ────────────────────────────────────
const desc = (d.jobDescription || '').slice(0, 500).trim() +
  (d.jobDescription?.length > 500 ? '...' : '');

// ── Build Telegram message ────────────────────────────────────
const lines = [
  `${grade} <b>New Upwork Lead</b>`,
  ``,
  `📌 <b><a href="${d.jobUrl}">${d.jobTitle}</a></b>`,
  ``,
  `📝 ${desc}`,
  ``,
  `━━━━━━━━━━━━━━━━━━`,
  `💼 <b>Job Details</b>`,
  `• <b>Type:</b> ${d.jobType}`,
  `• <b>Category:</b> ${d.jobCategory}`,
  `• <b>Budget:</b> ${budgetStr}`,
  `• <b>Skills:</b> ${d.skills || 'N/A'}`,
  `• <b>Posted:</b> ${new Date(d.postedOn).toLocaleDateString()}`,
  `• <b>Applicants:</b> ${d.totalApplicants} | Interviews: ${d.totalInvitedToInterview}`,
  ``,
  `━━━━━━━━━━━━━━━━━━`,
  `🏢 <b>Client Info</b>`,
  `• <b>Company:</b> ${d.companyName || 'Unknown'}${nameSourceBadge}${personLine}`,
  `• <b>Location:</b> ${d.clientCity}, ${d.clientCountry}`,
  `• <b>Member since:</b> ${d.companyContractDate ? new Date(d.companyContractDate).getFullYear() : 'N/A'}`,
  ``,
  `━━━━━━━━━━━━━━━━━━`,
  `📊 <b>Client History</b>`,
  `• <b>Total Spent:</b> ${spentStr}`,
  `• <b>Rating:</b> ${d.clientScore}/5 (${d.feedbackCount} reviews)`,
  `• <b>Jobs Posted:</b> ${d.totalJobsPosted} | Hired: ${d.totalHired}`,
  `• <b>Active Contracts:</b> ${d.activeContracts}`,
  `• <b>Hours Logged:</b> ${d.totalHoursWorked}`,
  `• <b>Payment:</b> ${d.paymentVerified ? '✅ Verified' : '❌ Not verified'}`,
  `• <b>Enterprise:</b> ${d.enterprise ? '✅ Yes' : 'No'}`,
  ``,
  `━━━━━━━━━━━━━━━━━━`,
  `👥 <b>Team Members</b>`,
  staffLines,
  ``,
  `━━━━━━━━━━━━━━━━━━`,
  `🏆 <b>Lead Score: ${score}/100 — ${grade}</b>`,
  reasons.join(' | '),
].filter(l => l !== null).join('\n');

const message = lines.length > 4096 ? lines.slice(0, 4090) + '...' : lines;

return [{
  json: {
    ...d,
    leadScore: score,
    leadGrade: grade,
    message,
    budgetFormatted: budgetStr,
    spentFormatted: spentStr,
    staffFormatted: staffs.map(s => s.name).join(', '),
    scoreReasons: reasons.join(', ')
  }
}];
